var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"검사 결과, 체내의 침식 바이러스는 모두 소멸했어요.","JPN":"検査結果、体内の侵食ウイルスはすべて消滅しました。","ENG":"The test results show that the internal Corruption virus has been completely eradicated.","TWN":"檢查結果顯示，體內的侵蝕病毒已經完全消滅了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"이제 한 시름 덜었군요. 고생하셨어요, 경관님.","JPN":"これで一安心です。お疲れ様でした、お巡りさん。","ENG":"At least that's one worry off our shoulders. Great work, officer.","TWN":"現在可以稍微鬆口氣了。辛苦了，警官。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다른 피해자들은 어떻죠?","JPN":"他の被害者はどうしていますか？","ENG":"What about the other victims?","TWN":"其他受害者情況如何？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"환자 검진은 제 소관이 아니라서요. 다들 멀쩡히 깨어났으니 괜찮겠죠.","JPN":"患者の診断は私の管轄外なので。みなさん無事目覚めたので大丈夫でしょう。","ENG":"I'm not in charge of patient exams, but everyone seems to have woken up fine.","TWN":"患者的檢查不歸我管。但大家都已經醒過來了，應該沒問題的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"애니 양도 무사히 회복하고 있대요. 그러니 한숨 돌리세요, 경정님.","JPN":"エニーさんも無事回復しているそうです。だから休んでください、警視様。","ENG":"Annie is recovering well too. So rest assured, Major.","TWN":"安妮也在順利康復，所以可以稍稍放寬心了，長官。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위도 고생 많았어.","JPN":"マエカワ警部補もお疲れ様。","ENG":"Lieutenant Kang, good work.","TWN":"姜素英警官，你也辛苦了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"뭐, 저도 최선을 다하긴 했지만… 진짜로 활약을 하신 분은 따로 있으니까요.","JPN":"まぁ、私も最善を尽くしましたけど……本当に活躍した方は他にいますから。","ENG":"Well, I did my best, but the real hero is someone else.","TWN":"嗯，雖然我也盡力了……但真正起到關鍵作用的另有其人。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"나중에 한 번 찾아가서 정식으로 감사인사를 드리죠.","JPN":"後日訪ねて行って正式にお礼を言いましょう。","ENG":"We should go visit later and thank her properly.","TWN":"以後找時間正式去感謝一下她吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"솔로베 말이지? 지금은 어디에 있는데?","JPN":"ソロベーのことね？　今はどこにいるの？","ENG":"You're talking about Solovey, right? Where is she?","TWN":"你是說蘇羅薇嗎？她現在在哪？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"쇼핑을 다녀온다던데요?","JPN":"ショッピングに行くらしいですよ？","ENG":"I heard she's out shopping?","TWN":"聽說她去逛街了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"오오…!","JPN":"おお……！","ENG":"Wow...!","TWN":"哇喔……！"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"LAUGH2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이거 귀여워요! 이것도!","JPN":"これ可愛いです！　これも！","ENG":"This one's cute! And this one too!","TWN":"好可愛！這個也好可愛！"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"LAUGH2"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여기 있는 인형 전부 다 주세요!!","JPN":"ここにあるぬいぐるみ全部ください！！","ENG":"I'll take all the dolls here, please!!","TWN":"請把這裡所有的娃娃都幫我包起來！"},"stage":{"bg":"STORE","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"감사합니다. 직원들이 포장할 동안 잠시 기다려주세요.","JPN":"ありがとうございます。店員がいま包装いたしますので、少々お待ちください。","ENG":"Thank you. Please wait a moment while the staff wraps it up.","TWN":"謝謝你，那麼在店員包裝的時候，請你稍等一下。"},"stage":{"bg":"STORE","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"솔로베, 정말 괜찮겠어?","JPN":"ソロベー、本当に大丈夫？","ENG":"Solovey, are you really sure about this?","TWN":"蘇羅薇，真的沒問題嗎？"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"기껏 받아낸 관리국 보수금을 인형에다 전부 써버려도?","JPN":"せっかく管理局から貰った報酬なのに全部ぬいぐるみに使って。","ENG":"You're really spending the whole reward from the Administration on dolls?","TWN":"好不容易拿到了管理局獎金，全都花在娃娃上沒關係嗎？"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아요. 돈은 가지고 있는 것보다 좋아하는 일에 쓰는 게 더 즐겁거든요.","JPN":"大丈夫です。お金は持っているより自分が好きなことに使う方が楽しいですから。","ENG":"It's fine. Spending money on what I love is more enjoyable than having it.","TWN":"沒關係的，與其把錢握在手裡，不如花在喜歡的事情上還更開心些，不是嗎？"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"뭐… 틀린 말은 아니네.","JPN":"まあ……間違ってはないけど。","ENG":"Well, you're not wrong.","TWN":"嗯……也對。"},"stage":{"bg":"STORE","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데 언니는 여기 와도 돼요? 병원에서 치료받지 않아도 되나요?","JPN":"ところで姉さんはここにいてもいいんですか？　病院で治療を受けた方が、いいんじゃないですか？","ENG":"Are you sure you can be here, Sis? Shouldn't you be at the hospital for treatment?","TWN":"但姊姊，你這樣出來真的可以嗎？不用留在醫院治療嗎？"},"stage":{"bg":"STORE","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"견딜 만해. 병원 신세 진 지 얼마 안 됐는데, 또 소독약 냄새를 맡고 싶지도 않고.","JPN":"我慢できるくらいよ。退院してからそう経っていないのに、また消毒薬の匂いを嗅ぐのも嫌だから。","ENG":"I can handle it. I just got out of the hospital, and I don't want to smell antiseptic again.","TWN":"還撐得住。前段時間才住過院，不想這麼快又聞到消毒藥水的味道。"},"stage":{"bg":"STORE","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"돌아가는 길엔 같이 돈까스나 먹을까? 괜찮은 맛집을 알거든.","JPN":"帰りに一緒にとんかつでも食べる？　美味しい店を知ってるの。","ENG":"How about we get some pork cutlets on the way back? I know a great place.","TWN":"回去的路上一起去吃炸豬排怎麼樣？我知道一家好吃的店。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗…! 네에! 먹을래요!","JPN":"あっ……！　はい！　食べます！","ENG":"Ah...! Yes! I'd love to!","TWN":"啊……！好啊，我想吃！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"LAUGH2"}}}}]`);export{e as default};